content.text:
    /** Drain queued microtasks enough times for the upload loop + re-render. */
    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    /**
     * Build a fetch impl that rejects POST /upload for the named files (via a
     * non-ok Response, exactly how `ApiClient.request` surfaces failures) while
     * still serving normal browse/upload responses for everything else.
     */
    function failingUploadImpl(failingNames: string[]) {
      const failing = new Set(failingNames);
      return async (url: string, init?: RequestInit): Promise<Response> => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && failing.has(file.name)) {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          const raw = u.split('path=')[1] ?? '';
          const path = decodeURIComponent(raw);
          const child = 'child-of-' + (path || 'root');
          return mockResponse({
            body: browseResult({
              path,
              entries: [fileEntry({ name: child, path: joinPathHelper(path, child) })],
              fileCount: 1,
              totalSize: 10,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      };
    }

    /** Ordered names of files POSTed to /upload so far. */
    function uploadedFileNames(): string[] {
      return fetchMock.mock.calls
        .filter(([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST')
        .map(([, init]) => ((init?.body as FormData | undefined)?.get('file') as File | null)?.name ?? '');
    }

    /** Count of GET /browse calls observed so far. */
    function browseCount(): number {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/browse') && (init?.method ?? 'GET') === 'GET',
      ).length;
    }

    it('uploads each selected file to the current browse path, then clears the input and re-renders', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await flush();
      await flush();

      const uploadCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
      expect(uploadCalls).toHaveLength(2);
      for (const [, init] of uploadCalls) {
        expect(init?.body).toBeInstanceOf(FormData);
        expect((init!.body as FormData).get('file')).toBeInstanceOf(File);
      }
      // All uploads target the current browse path.
      expect(uploadCalls.every(([u]) => String(u).includes('path=' + encodeURIComponent('docs')))).toBe(true);
      // The input is cleared afterwards.
      expect(uploadInput.value).toBe('');
      // And a re-render occurred (browse fetched again after upload).
      const browseCalls = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse'));
      expect(browseCalls.length).toBeGreaterThan(0);
    });

    it('uploads nothing when no files are selected', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      uploadInput.dispatchEvent(new Event('change'));
      await flush();

      expect(
        fetchMock.mock.calls.some(([u]) => String(u).includes('/upload')),
      ).toBe(false);
    });

    // ---- per-file error handling -------------------------------------------
    // A single failing upload must NOT abort the remaining uploads, swallow the
    // re-render, or leave the input uncleared. Each failure is surfaced in the
    // status footer (see task spec: "Uploaded N file(s); failed: a.txt, b.txt").

    it('continues uploading the remaining files when a middle upload fails, then clears the input, re-renders, and surfaces the failure', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['b.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['a.txt', 'b.txt', 'c.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      // All three uploads were attempted — including the failing one — in order.
      expect(uploadedFileNames()).toEqual(['a.txt', 'b.txt', 'c.txt']);
      // The input is cleared even though one upload failed.
      expect(uploadInput.value).toBe('');
      // A re-render still happened after the upload loop.
      expect(browseCount()).toBeGreaterThan(browseBefore);
      // The failure is surfaced in the status footer: it names the failing
      // file and acknowledges the two files that did upload.
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('b.txt');
      expect(status.textContent).toMatch(/Uploaded\s+2/i);
      // Successful files are not flagged as failed.
      expect(status.textContent).not.toContain('c.txt');
      expect(status.textContent).not.toContain('a.txt');
    });

    it('continues uploading subsequent files when the first upload fails', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['bad.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['bad.txt', 'good.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['bad.txt', 'good.txt']);
      expect(uploadInput.value).toBe('');
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });

    it('clears the input, re-renders, and lists every failure when all uploads fail', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['x.txt', 'y.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['x.txt', 'y.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['x.txt', 'y.txt']);
      expect(uploadInput.value).toBe('');
      expect(browseCount()).toBeGreaterThan(browseBefore);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('x.txt');
      expect(status.textContent).toContain('y.txt');
    });

    it('does not surface a failure message when every upload succeeds (status stays the normal browse summary)', async () => {
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadInput.value).toBe('');
      // No failure report; renderBrowse's normal "N folders, M files, total S"
      // summary is what the re-render leaves behind.
      expect(status.textContent).not.toMatch(/failed/i);
      expect(status.textContent).toMatch(/folders.*files.*total/);
    });
  });
});

/* ===========================================================================
 * Import characterization (safety net for unused-import removal)
 *
 * `src/app.ts` imports `parseHash` (from ./router.js), `parentPath`, and
 * `basename` (from ./format.js) that are never referenced in the module body
 * and are slated for removal. Removing unused imports cannot change runtime
 * behavior, so these tests guard the OTHER behaviors: they pin the observable
 * outputs that depend on the imports which STAY — especially the ones that
 * share an import line with the removed names, where a careless edit could
 * drop a needed sibling. Each assertion checks a concrete value tied to one
 * retained import's real usage in the app; if that import were removed, the
 * referenced call would throw (ReferenceError) or emit wrong output and the
 * test would fail.
 *
 * Retained imports exercised here:
 *   format.js: joinPath, normalizeRelativePath, formatBytes, formatDate
 *   router.js: toBrowseHash, toSearchHash
 * (getCurrentRoute / subscribe / navigate are already covered by the render
 * orchestration and toolbar-handler suites above.)
 * ========================================================================= */
describe('import characterization (KEEP-list behaviors)', () => {
  // Local leaf finder; the breadcrumb describe has its own scoped copy.
  function leafByText(container: Element, text: string): HTMLElement | undefined {
    return Array.from(container.querySelectorAll('*')).find(
      (el) => el.children.length === 0 && (el.textContent ?? '').trim() === text,
    ) as HTMLElement | undefined;
  }

  /* --- format.js KEEP imports (siblings of the removed parentPath/basename) --- */

  describe('joinPath (breadcrumb cumulative paths)', () => {
    it('joins each cumulative segment across three path levels', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }));

      leafByText(breadcrumb, 'c')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b/c'));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('normalizeRelativePath (breadcrumb path cleaning)', () => {
    it('collapses leading/doubled/trailing slashes before splitting segments', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '//a//b//' }));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('formatBytes (size column)', () => {
    it('renders a 0-byte file as "0 B" (sub-KB integer branch)', async () => {
      const entry = fileEntry({ name: 'empty.txt', path: 'docs/empty.txt', size: 0 });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const sizeCell = cellsOf(rowByName(results.querySelector('table')!, 'empty.txt')!)[1];
      expect(sizeCell.textContent?.trim()).toBe('0 B');
    });
  });

  describe('formatDate (modified column)', () => {
    it('renders an empty Modified cell when lastModified is empty (fallback)', async () => {
      const entry = fileEntry({ name: 'nodate.txt', path: 'docs/nodate.txt', lastModified: '' });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const modifiedCell = cellsOf(rowByName(results.querySelector('table')!, 'nodate.txt')!)[2];
      expect(modifiedCell.textContent).toBe('');
    });
  });

  /* --- router.js KEEP imports (siblings of the removed parseHash) --- */

  describe('toBrowseHash (per-segment percent-encoding)', () => {
    it('encodes spaces in directory names when navigating into a folder', async () => {
      const dir = fileEntry({ name: 'my folder', path: 'docs/my folder', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

      clickNameLink(rowByName(results.querySelector('table')!, 'my folder')!);

      expect(window.location.hash).toBe('#/browse/docs/' + encodeURIComponent('my folder'));
      expect(window.location.hash).toBe(toBrowseHash('docs/my folder'));
    });
  });

  describe('toSearchHash (query/path percent-encoding)', () => {
    it('encodes special characters in the search query and scope path', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'a & b=c?';
      searchBtn.click();

      const expected =
        '#/search?q=' + encodeURIComponent('a & b=c?') + '&path=' + encodeURIComponent('docs');
      expect(window.location.hash).toBe(expected);
      expect(window.location.hash).toBe(toSearchHash('a & b=c?', 'docs'));
    });
  });
});

/* ===========================================================================
 * Rendering lifecycle
 *
 * Two interrelated startApp/render bugs are pinned here:
 *
 *  (a) LISTENER LEAK — startApp calls subscribe(render) and used to throw away
 *      the returned unsubscribe function, so every re-mount left the previous
 *      mount's hashchange listener on `window`. (happy-dom dedups identical
 *      function references, so this leak is latent rather than multiplicative
 *      in this environment, but the cleanup contract is still asserted via the
 *      addEventListener/removeEventListener spies below.)
 *  (b) RENDER RACE — render() is async; two rapid navigations let a slower
 *      fetch overwrite a fresher one's results. The fix aborts a superseded
 *      render after each await.
 * ========================================================================= */
describe('rendering lifecycle', () => {
  describe('hashchange listener cleanup on re-mount', () => {
    /**
     * Mount the app `n` times into fresh containers, the way `setup()` does.
     * Returns nothing; used to drive repeated startApp() calls with the spies
     * already installed so every subscribe/unsubscribe is captured.
     */
    function mountNTimes(n: number): void {
      for (let i = 0; i < n; i++) {
        document.body.innerHTML = '';
        window.location.hash = '';
        const root = document.createElement('div');
        document.body.append(root);
        startApp(root);
      }
    }

    function hashchangeCalls(
      spy: ReturnType<typeof vi.spyOn>,
    ): Array<{ type: string; callback: EventListenerOrEventListenerObject }> {
      return spy.mock.calls
        .map(([type, callback]) => ({ type: String(type), callback }))
        .filter((c) => c.type === 'hashchange');
    }

    it('subscribes exactly one hashchange listener per mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');

      mountNTimes(3);
      await flush();

      // Each startApp() subscribes render exactly once.
      expect(hashchangeCalls(addSpy)).toHaveLength(3);
    });

    it('unsubscribes the previous mount\'s hashchange listener on every re-mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');
      const removeSpy = vi.spyOn(window, 'removeEventListener');

      const N = 4;
      mountNTimes(N);
      await flush();

      const adds = hashchangeCalls(addSpy);
      const removes = hashchangeCalls(removeSpy);

      // Robust to test ordering: the 1st mount in *this* test may additionally
      // tear down a listener left over by an earlier test, so we only assert a
      // lower bound. The invariant that matters is that every re-mount removes
      // its predecessor — i.e. at least (N − 1) hashchange removals happened.
      // The leaky implementation performs ZERO removals.
      expect(adds).toHaveLength(N);
      expect(removes.length).toBeGreaterThanOrEqual(N - 1);
      // Every removal targets the same render callback that was subscribed.
      expect(removes.length).toBeGreaterThan(0);
      for (const r of removes) {
        expect(typeof r.callback).toBe('function');
        expect(adds.some((a) => a.callback === r.callback)).toBe(true);
      }
    });
  });

  describe('render race (superseded fetch is discarded)', () => {
    /**
     * Drive a browse render for `path` whose fetch is held open until the
     * caller invokes `release()`. All other browse paths resolve immediately.
     */
    function stubHeldBrowse(
      heldPath: string,
    ): { release: () => void } {
      let release!: () => void;
      const held = new Promise<Response>((resolve) => {
        release = () =>
          resolve(
            mockResponse({
              body: browseResult({
                path: heldPath,
                entries: [
                  fileEntry({
                    name: 'child-of-' + heldPath,
                    path: joinPathHelper(heldPath, 'child-of-' + heldPath),
                  }),
                ],
                fileCount: 1,
                totalSize: 1,
              }),
            }),
          );
      });

      fetchMock.mockImplementation(async (url, init) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'GET' && u.includes('/browse')) {
          const path = decodeURIComponent(u.split('path=')[1] ?? '');
          if (path === heldPath) {
            return held;
          }
          return mockResponse({
            body: browseResult({
              path,
              entries: [
                fileEntry({
                  name: 'child-of-' + path,
                  path: joinPathHelper(path, 'child-of-' + path),
                }),
              ],
              fileCount: 1,
              totalSize: 1,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      });

      return { release };
    }

    it('does not let a slower, superseded browse overwrite the latest results', async () => {
      const { release } = stubHeldBrowse('slow');

      const { results } = setup();
      await flush(); // settle the initial render for the default route

      // Navigate to 'slow' (its fetch is held), then — before it resolves — to
      // 'fast'. In happy-dom each hash assignment fires `hashchange` and thus
      // render() synchronously, so both fetches are issued in order and the
      // 'slow' render is suspended at its await when 'fast' starts.
      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush(); // 'fast' resolves first and commits

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');

      // The slow fetch finally resolves LAST. Its stale data must be discarded
      // (a newer render owns the slot) and must NOT clobber the fresh results.
      release();
      await flush();

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');
    });

    it('does not let a superseded browse update the breadcrumb or status', async () => {
      const { release } = stubHeldBrowse('slow');

      const { breadcrumb, status } = setup();
      await flush();

      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush();

      // The fresh render owns the breadcrumb / status for 'fast'.
      expect(breadcrumb.textContent).toContain('fast');
      expect(status.textContent).toContain('1 files');

      release();
      await flush();

      // The superseded 'slow' render must not have touched them.
      expect(breadcrumb.textContent).toContain('fast');
      expect(breadcrumb.textContent).not.toContain('slow');
      expect(status.textContent).toContain('1 files');
    });

    it('still renders the latest navigation when fetches resolve in order', async () => {
      // Control case: a single navigation (no race) still commits normally,
      // so the race guard does not swallow a non-superseded render.
      const { results } = setup({ hash: toBrowseHash('solo') });
      await flush();

      expect(results.textContent).toContain('child-of-solo');

      navigate(toBrowseHash('next'));
      await flush();

      expect(results.textContent).toContain('child-of-next');
      expect(results.textContent).not.toContain('child-of-solo');
    });
  });
});

/* ===========================================================================
 * Dead CSS selector characterization
 *
 * `src/app.css` ships rule blocks whose selectors are NEVER emitted by app.ts,
 * so they have ZERO observable effect on the rendered UI. They are slated for
 * deletion in a dead-code cleanup. The tests below pin the JS-side invariants
 * that make that deletion provably safe:
 *
 *   - the rendered DOM must never produce an element the removed selectors
 *     could match; and
 *   - any behavior the dead rules *appear* to supply must actually be provided
 *     by an independent mechanism that survives the deletion.
 *
 * Removed selectors under test:
 *   (1) `.results-table .folder-row td`  — no table row is ever given the
 *       `folder-row` class.
 *   (2) `.breadcrumb .separator`         — breadcrumb separators are class-less
 *       `<span>`s holding the literal "/"; nothing carries `separator`.
 *   (3) `.toolbar label.upload-btn` (+ its `:hover` + the descendant
 *       `input[type=file]` rule) — the upload label uses `btn`, never
 *       `upload-btn`, and the wrapped file input is hidden via the `hidden`
 *       HTML attribute, not via the dead `display:none` descendant rule.
 *
 * These assertions pass against the current (pre-cleanup) code AND must keep
 * passing after the dead rules are deleted, because they depend only on the
 * DOM app.ts emits — which the cleanup does not touch. (The environment does
 * not load app.css, so a missing rule cannot change `getComputedStyle` here;
 * these tests instead prove the rule could never have matched anything.)
 * ========================================================================= */
describe('dead CSS selector characterization', () => {
  describe('folder rows never carry the dead `.folder-row` class', () => {
    it('browse rows (folder, file, and the ".." parent) all have an empty className and no `folder-row`', async () => {
